index c3f296b9ff33..091fdb5d3a4a 100644
--- a/llvm/lib/Analysis/ScalarEvolution.cpp
+++ b/llvm/lib/Analysis/ScalarEvolution.cpp
@@ -14345,6 +14345,28 @@ void ScalarEvolution::verify() const {
     const SCEV *visitCouldNotCompute(const SCEVCouldNotCompute *Expr) {
       return SE.getCouldNotCompute();
     }
+
+    const SCEV *visitAddRecExpr(const SCEVAddRecExpr *Expr) {
+      SmallVector<const SCEV *, 2> Operands;
+      bool Changed = false;
+      for (const auto *Op : Expr->operands()) {
+        Operands.push_back(visit(Op));
+        Changed |= Op != Operands.back();
+      }
+      
+      // Check if all operands are available at the loop entry.
+      // If not, return CouldNotCompute to avoid assertion failures
+      // during verification after loop transformations.
+      const Loop *L = Expr->getLoop();
+      for (const SCEV *Op : Operands) {
+        if (!SE.isAvailableAtLoopEntry(Op, L)) {
+          return SE.getCouldNotCompute();
+        }
+      }
+      
+      return !Changed ? Expr
+                      : SE.getAddRecExpr(Operands, L, Expr->getNoWrapFlags());
+    }
   };

   SCEVMapper SCM(SE2);
