+static bool isSCEVValidForVerification(const SCEV *S, ScalarEvolution &SE) {
+  // Check if all AddRecExpr operands are available at their loop entries.
+  if (const auto *AR = dyn_cast<SCEVAddRecExpr>(S)) {
+    const Loop *L = AR->getLoop();
+    for (const SCEV *Op : AR->operands()) {
+      if (!SE.isAvailableAtLoopEntry(Op, L))
+        return false;
+    }
+  }
+
+  // Recursively check operands for other SCEV types.
+  for (const SCEV *Op : S->operands()) {
+    if (!isSCEVValidForVerification(Op, SE))
+      return false;
+  }
+  
+  return true;
+}
